+        while (i + num_offsets * 4 < data.len) : (i += 4) {
+            const first = std.mem.readInt(i32, data[i..][0..4], .little);
+            if (first != 0) continue;
+
+            // Check if this looks like valid offsets
+            var valid = true;
+            var last: i32 = 0;
+            for (0..num_offsets) |j| {
+                const off = std.mem.readInt(i32, data[i + j * 4 ..][0..4], .little);
