+            const data_start = off_start + num_offsets * 4;
+
+            for (0..self.num_rows) |j| {
+                const start_off = std.mem.readInt(i32, data[off_start + j * 4 ..][0..4], .little);
+                const end_off = std.mem.readInt(i32, data[off_start + (j + 1) * 4 ..][0..4], .little);
